array_filter(
					array(
						'_Premium'  => defined( 'YITH_WCWL_PREMIUM' ) && YITH_WCWL_PREMIUM,
						'_Extended' => defined( 'YITH_WCWL_EXTENDED' ) && YITH_WCWL_EXTENDED,
					)
				)

array_filter(
				$this->get_render_data(),
				function ( $value, $name ) use ( $global_options ) {
					return $value !== ( $global_options[ $name ] ?? null );
				},
				ARRAY_FILTER_USE_BOTH
			)

array_filter(
				$icons,
				function ( $icon ) use ( $context ) {
					return is_array( $context ) ? array_intersect( $context, $icon[ 'tags' ] ) : in_array( $context, $icon[ 'tags' ], true );
				}
			)

$wpdb->get_col(
					$wpdb->prepare(
						"SELECT ID FROM {$wpdb->posts} AS posts WHERE posts.post_type = 'shop_order' AND posts.ID LIKE %s",
						'%' . $wpdb->esc_like( $term ) . '%'
					)
				)

array_filter(
					array(
						'currency' => function_exists( 'get_woocommerce_currency' ) ? get_woocommerce_currency() : null,
						'lang'     => get_locale(),
					)
				)

usort(
					$sorted_plugins,
					function ( $a, $b ) {
						return strcmp( current( $a ), current( $b ) );
					}
				)

printf(
					'<button type="button" class="toggle-row"><span class="screen-reader-text">%s</span></button>',
					// translators: Hidden accessibility text.
					esc_html__( 'Show more details', 'yith-plugin-fw' )
				)

array_map(
			function ( $key ) use ( $array ) {
				return isset( $array[ $key ] ) ? $array[ $key ] : null;
			},
			$keys
		)

array_map(
			function ( $init_file ) {
				$name = get_plugin_data( WP_PLUGIN_DIR . '/' . $init_file )['Name'] ?? '';
				if ( ! $name ) {
					$name = str_replace( array( '-', 'init.php', '/' ), ' ', $init_file );
					$name = str_replace( array( 'yith', 'woocommerce', 'wordpress' ), array( 'YITH', 'WooCommerce', 'WordPress' ), $name );
					$name = trim( ucwords( $name ) );
				}

				return $name;
			},
			$names
		)

